1	---
2	/**
3	 * EmailGate — wraps content behind an email capture form.
4	 * Checks localStorage for unlock state. On submit, POSTs to /capture
5	 * (Cloudflare Pages Function) and unlocks client-side.
6	 *
7	 * Usage:
8	 *   <EmailGate>
9	 *     <div>Protected content here</div>
10	 *   </EmailGate>
11	 *
12	 * Props:
13	 *   preview — optional teaser text shown above the gate
14	 */
15	interface Props {
16	  preview?: string;
17	}
18	
19	const { preview } = Astro.props;
20	---
21	
22	<div class="email-gate-wrapper">
23	  <!-- Gated content (hidden until unlocked) -->
24	  <div id="gated-content" class="hidden opacity-0 transition-opacity duration-700">
25	    <slot />
26	  </div>
27	
28	  <!-- Gate form (visible until unlocked) -->
29	  <div id="gate-overlay" class="py-20 px-6">
30	    {preview && (
31	      <div class="max-w-[640px] mx-auto mb-12 text-white/35 text-[16px] font-light leading-[1.9] text-center">
32	        <p>{preview}</p>
33	      </div>
34	    )}
35	    <div class="max-w-md mx-auto">
36	      <div class="glass-card p-10 text-center" style="border-color: rgba(17,154,158,0.15);">
37	        <div class="w-10 h-px bg-ocean-500/30 mx-auto mb-6"></div>
38	        <h2 class="font-heading text-[26px] font-light text-white mb-3">Continue reading</h2>
39	        <p class="text-white/35 text-[15px] font-light mb-8 leading-relaxed">
40	          Enter your email to unlock the full research-backed deep dive. Backed by 263 peer-reviewed and sacred sources.
41	        </p>
42	
43	        <form id="gate-form" class="space-y-4">
44	          <input
45	            type="email"
46	            required
47	            placeholder="your@email.com"
48	            class="w-full bg-ocean-800/50 border border-ocean-500/20 rounded-lg px-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-ocean-400 transition-colors text-[15px]"
49	          />
50	          <button
51	            type="submit"
52	            class="w-full bg-ocean-500 hover:bg-ocean-400 text-white font-medium py-3 rounded-lg transition-all shadow-lg shadow-ocean-500/10 active:scale-[0.98] text-[14px]"
53	          >
54	            Unlock
55	          </button>
56	        </form>
57	
58	        <p class="mt-6 text-[10px] text-white/15 uppercase tracking-[0.15em]">
59	          No spam. Only sovereignty.
60	        </p>
61	      </div>
62	    </div>
63	  </div>
64	</div>
65	
66	<script>
67	  const content = document.getElementById('gated-content');
68	  const overlay = document.getElementById('gate-overlay');
69	  const form = document.getElementById('gate-form') as HTMLFormElement;
70	  const UNLOCK_KEY = 'ss_unlocked';
71	
72	  function unlock() {
73	    if (overlay && content) {
74	      overlay.classList.add('hidden');
75	      content.classList.remove('hidden');
76	      setTimeout(() => content.classList.remove('opacity-0'), 10);
77	    }
78	  }
79	
80	  if (localStorage.getItem(UNLOCK_KEY) === 'true') {
81	    unlock();
82	  }
83	
84	  form?.addEventListener('submit', async (e) => {
85	    e.preventDefault();
86	    const emailInput = form.querySelector('input[type="email"]') as HTMLInputElement;
87	    const button = form.querySelector('button[type="submit"]') as HTMLButtonElement;
88	    const email = emailInput.value;
89	
90	    if (email) {
91	      const originalText = button.innerText;
92	      button.innerText = 'Unlocking...';
93	      button.disabled = true;
94	
95	      try {
96	        await fetch('/capture', {
97	          method: 'POST',
98	          headers: { 'Content-Type': 'application/json' },
99	          body: JSON.stringify({ email })
100	        });
101	        localStorage.setItem(UNLOCK_KEY, 'true');
102	        unlock();
103	      } catch {
104	        button.innerText = originalText;
105	        button.disabled = false;
106	        // Still unlock on network failure — don't block the UX
107	        localStorage.setItem(UNLOCK_KEY, 'true');
108	        unlock();
109	      }
110	    }
111	  });
112	</script>
